    console.log('=== INITIALIZING CHARTS ===');
    // Charts are initialized when their respective functions are called
    console.log('Charts ready');
}

function refreshDashboard() {
    fetchElectricityData();
    fetchSavingsData();
    updateDateDisplay(currentPeriod);
}

